class Solution:
    def makeGood(self, s: str) -> str:
        chars = list(s)
        changed = True
        while changed:
            changed = False
            i = 0
            while i < len(chars) - 1:
                if chars[i] != chars[i + 1] and chars[i].lower() == chars[i + 1].lower():
                    del chars[i:i + 2]
                    changed = True
                    i = max(i - 1, 0)
                else:
                    i += 1
        return ''.join(chars)

