var makeGood = function(s) {
    const stack = [];
    for (const c of s) {
        const top = stack[stack.length - 1];
        if (top !== undefined && top !== c && top.toLowerCase() === c.toLowerCase()) {
            stack.pop();
        } else {
            stack.push(c);
        }
    }
    return stack.join('');
};
